    </div>

    <div class="text-gray-900 dark:text-gray-100 min-h-screen">
      <!-- 导航栏 -->
      <nav class="sticky top-0 z-10 transition-all duration-300" :class="isScrolled ? 'bg-gradient-to-r backdrop-blur-md shadow-lg' : 'bg-transparent'">
        <div class="container mx-auto px-4 py-3 flex justify-between items-center">
          <div class="flex items-center space-x-2">
            <!-- 头像下拉菜单 -->
            <div class="relative user-menu-container">
              <img
                :src="options.user.avatar"
                alt="头像"
                class="w-8 h-8 rounded-full cursor-pointer hover:ring-2 hover:ring-blue-500 transition-all duration-200"
                @click="toggleUserMenu"
              >
              <!-- 下拉菜单 -->
              <div
                v-show="showUserMenu"
                class="global-card absolute left-0 mt-2 w-48 bg-white dark:bg-gray-800 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 z-[100] transition-all duration-200 animate-scale-in"
                :class="showUserMenu ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-2'"
                @click.stop
              >
                <!-- 用户信息 -->
                <div class="px-4 py-3 border-b border-gray-200 dark:border-gray-700">
                  <p class="text-sm font-medium text-gray-900 dark:text-gray-100">{{ options.user.account }}</p>
                  <p class="text-xs text-gray-500 dark:text-gray-400">{{ options.user.email }}</p>
                </div>
                <!-- 菜单项 -->
                <div class="py-1">
                  <button
                    @click="goToProfile"
                    class="w-full text-left px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center"
                  >
                    <svg class="w-4 h-4 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path>
                    </svg>
                    个人信息
                  </button>
                  <button
                    @click="switchAccount"
                    class="w-full text-left px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center"
                  >
                    <svg class="w-4 h-4 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
                    </svg>
                    切换账号
                  </button>
                  <hr class="my-1 border-gray-200 dark:border-gray-700">
                  <button
                    @click="logout"
                    class="w-full text-left px-4 py-2 text-sm text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center"
                  >
                    <svg class="w-4 h-4 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path>
                    </svg>
                    退出登录
                  </button>
                </div>
              </div>
            </div>
            <span class="text-xl font-bold transition-colors duration-300 text-gray-800">{{ options.user.account }}</span>
          </div>
          <!-- 主导航菜单 - 使用navSections数据 -->
          <div class="hidden md:flex items-center justify-center flex-1 space-x-8">
            <template v-for="section in navSections" :key="section.label">
              <!-- 有子菜单的项 -->
              <div v-if="section.items.length > 1" class="relative group">
                <button
                  class="py-2 text-base font-medium transition-colors duration-200 inline-flex items-center hover:text-gray-800/90"
                  :class="{'text-gray-800': !isScrolled || isScrolled, 'text-primary': section.items.some(item => $route.path === item.path)}"
                  @mouseenter="activeNavItem = section.items[0]?.id"
                  @click="navSections.indexOf(section) === 1 ? (showStyleModal = true) : null"
                >
                  <span class="inline-block w-5 h-5 mr-2" v-html="section.icon"></span>
                  {{ section.label }}
                  <svg class="w-4 h-4 ml-1 transition-transform duration-200 group-hover:rotate-180" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"></path>
                  </svg>
                </button>

                <!-- 居中显示的子菜单 -->
                <div class="global-card absolute left-1/2 transform -translate-x-1/2 -translate-y-2 mt-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 opacity-0 invisible scale-95 group-hover:opacity-100 group-hover:visible group-hover:translate-y-0 group-hover:scale-100 transition-all duration-300 ease-out z-50 p-2 min-w-max">
                  <div class="flex flex-row space-x-2 justify-center">
                    <router-link
                      v-for="item in section.items.filter(item => hasPermission(item))"
                      :key="item.id"
                      :to="item.path"
                      class="flex items-center px-4 py-2 text-sm rounded-lg transition-colors duration-200 whitespace-nowrap"
                      :class="{'bg-primary/10 text-primary': $route.path === item.path, 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 hover:text-primary': $route.path !== item.path}"
                      @click="activeNavItem = item.id"
                    >
                      <span class="inline-block w-5 h-5 mr-2" v-html="item.icon"></span>
                      {{ item.text }}
                    </router-link>
                  </div>
                </div>
              </div>

              <!-- 无子菜单的项（单个item） -->
              <router-link
                v-else-if="section.items.length === 1 && hasPermission(section.items[0])"
                :to="section.items[0].path"
                class="py-2 text-base font-medium transition-colors duration-200 hover:text-gray-800/90"
                :class="{'text-primary': $route.path === section.items[0].path, 'text-gray-800': !isScrolled || isScrolled}"
                @click="activeNavItem = section.items[0].id"
              >
                <span class="inline-block w-5 h-5 mr-2" v-html="section.icon"></span>
                {{ section.label }}
              </router-link>
            </template>
          </div>
          <div class="flex items-center space-x-4">

            <button @click="showSearch = !showSearch">
              <svg t="1772701164585" class="icon w-6 h-6" viewBox="0 0 1060 1024" version="1.1" xmlns="http://www.w3.org/2000/svg" p-id="20131" width="200" height="200"><path d="M272.144144 498.162162c-23.063063 0-36.900901-18.45045-36.900901-36.900901 0-133.765766 101.477477-244.468468 221.405406-244.468468 23.063063 0 36.900901 18.45045 36.900901 36.900901 0 23.063063-18.45045 36.900901-36.900901 36.900901-78.414414 0-142.990991 73.801802-142.990991 166.054054 0 23.063063-18.45045 41.513514-41.513514 41.513513z" fill="#29CCB6" p-id="20132"></path><path d="M1014.774775 917.90991l-184.504505-184.504505c59.963964-73.801802 96.864865-170.666667 96.864865-276.756756 0-244.468468-198.342342-442.810811-442.810811-442.810811S36.900901 212.18018 36.900901 456.648649s198.342342 442.810811 442.810811 442.81081c101.477477 0 198.342342-36.900901 272.144144-96.864864l184.504504 184.504504c9.225225 9.225225 23.063063 13.837838 36.900901 13.837838 13.837838 0 27.675676-4.612613 36.900901-13.837838 23.063063-13.837838 23.063063-50.738739 4.612613-69.189189zM142.990991 456.648649c0-189.117117 152.216216-341.333333 341.333333-341.333334s341.333333 152.216216 341.333334 341.333334-152.216216 341.333333-341.333334 341.333333S142.990991 645.765766 142.990991 456.648649z" fill="#4585F5" p-id="20133"></path></svg>
