                  <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                </svg>
                按回车搜索
              </div>
              <div v-if="searchResults.length > 0">
                找到 {{ searchResults.length }} 个结果
              </div>
            </div>
          </div>

          <!-- 搜索结果 -->
          <div class="max-h-96 overflow-y-auto">
            <div v-if="isSearching" class="flex items-center justify-center py-10">
              <div class="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
            <div v-else-if="searchResults.length === 0 && searchQuery.length > 1" class="text-center py-10 text-gray-500 dark:text-gray-400">
              <svg class="w-12 h-12 mx-auto mb-4 text-gray-300 dark:text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
              </svg>
              未找到相关结果
            </div>
            <div v-else-if="searchQuery.length === 0" class="text-center py-10 text-gray-500 dark:text-gray-400">
              <svg class="w-12 h-12 mx-auto mb-4 text-gray-300 dark:text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
              </svg>
              请输入关键词搜索
            </div>
            <div v-else class="space-y-4">
              <div
                v-for="result in searchResults"
                :key="result.id"
                @click="goToArticle(result.id)"
                class="p-4 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors cursor-pointer"
              >
                <div class="flex items-center justify-between mb-2">
                  <span class="px-2 py-1 bg-primary/10 text-primary rounded text-xs font-medium">{{ result.category }}</span>
                  <span class="text-xs text-gray-500 dark:text-gray-400">{{ result.date }}</span>
                </div>
                <h4 class="text-lg font-semibold text-gray-900 dark:text-gray-100 mb-2">{{ result.title }}</h4>
                <p class="text-sm text-gray-600 dark:text-gray-400 line-clamp-2">{{ result.excerpt }}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 全局外观设置弹窗 -->
      <div
