        class="fixed inset-0 z-50 flex items-center justify-center bg-black/40"
        @click.self="showStylePanel = false"
      >
        <div class="global-card bg-white dark:bg-gray-900 rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700 w-full max-w-md p-6">
          <h3 class="text-lg font-semibold mb-4 text-gray-900 dark:text-gray-100">
            全局外观设置
          </h3>
          <div class="space-y-4 text-sm">
            <div>
              <label class="block mb-1 text-gray-700 dark:text-gray-200">
                卡片透明度（{{ uiStore.cardOpacity.toFixed(2) }}）
              </label>
              <input
                type="range"
                min="0.3"
                max="1"
                step="0.05"
                v-model.number="uiStore.cardOpacity"
                class="w-full"
              />
            </div>
            <div>
              <label class="block mb-1 text-gray-700 dark:text-gray-200">
                模糊半径（{{ uiStore.cardBlur }} px）
              </label>
              <input
                type="range"
                min="0"
                max="20"
                step="1"
                v-model.number="uiStore.cardBlur"
                class="w-full"
              />
            </div>
            <div>
              <label class="block mb-1 text-gray-700 dark:text-gray-200">
                通用背景色
              </label>
              <div class="flex items-center gap-2">
                <input
                  type="color"
                  v-model="uiStore.pageBg"
                  class="w-10 h-8 p-0 border border-gray-300 dark:border-gray-700 rounded cursor-pointer"
                />
                <input
                  type="text"
                  v-model="uiStore.pageBg"
                  class="flex-1 px-3 py-1.5 rounded border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-xs"
                />
              </div>
            </div>
          </div>
          <div class="mt-6 flex justify-end gap-3">
            <button
              class="px-4 py-1.5 text-xs rounded border border-gray-300 dark:border-gray-700 text-gray-600 dark:text-gray-300"
              @click="showStylePanel = false"
            >
