                <div>
                  <h3 class="font-semibold">用户名：{{ options.user.account }}</h3>
                  <p class="text-sm opacity-80">邮箱：{{ options.user.email }}</p>
                </div>
              </div>
            </div>

            <nav class="space-y-2">
